async (params, browser) => {
  // Open Google Calendar
  await browser.open('https://calendar.google.com/calendar/r')

  // Wait for calendar to load
  await browser.waitForSelector('[role=\'main\'], [data-eventid], .FAxxKc', 20000)

  // Let calendar fully render
  await browser.wait(2000)

  // Click the search icon
  const open_search = await browser.evaluate(`const searchBtn = document.querySelector('[aria-label="Search"], #sb_cb50, button[data-tooltip="Search"], [jsname="LwgnTb"]'); if (searchBtn) { searchBtn.click(); await new Promise(r => setTimeout(r, 1500)); } else { return { error: 'Could not find search button' }; } return { search_opened: true }`)

  // Wait for search input field
  await browser.waitForSelector('input[aria-label=\'Search\'], input[aria-label=\'Search for people, events\'], input#sb_cb50, input[type=\'search\']', 10000)

  // Brief pause
  await browser.wait(500)

  // Type search query and press Enter
  const submit_search = await browser.evaluate(`const searchInput = document.querySelector('input[aria-label="Search"], input[aria-label="Search for people, events"], input#sb_cb50, input[type="search"]'); if (!searchInput) return { error: 'Could not find search input' }; searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); const nativeSet = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; nativeSet.call(searchInput, params.query); searchInput.dispatchEvent(new Event('input', { bubbles: true })); searchInput.dispatchEvent(new Event('change', { bubbles: true })); await new Promise(r => setTimeout(r, 500)); searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); searchInput.dispatchEvent(new KeyboardEvent('keypress', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); searchInput.dispatchEvent(new KeyboardEvent('keyup', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); return { query_submitted: true }`)

  // Wait for search results to load
  await browser.wait(4000)

  // Scrape search results
  const search_results = await browser.evaluate(`const results = []; const eventElements = document.querySelectorAll('[data-eventid], [data-eventchip], .FAxxKc, [data-searchresultid], [role="listitem"]'); const seen = new Set(); eventElements.forEach(el => { if (results.length >= 30) return; const eventId = el.getAttribute('data-eventid') || el.getAttribute('data-eventchip') || el.getAttribute('data-searchresultid') || ''; if (eventId && seen.has(eventId)) return; if (eventId) seen.add(eventId); const ariaLabel = el.getAttribute('aria-label') || ''; let title = ''; let date = ''; let time = ''; if (ariaLabel) { title = ariaLabel; const dateMatch = ariaLabel.match(/(\w+day,\s+\w+\s+\d{1,2}(?:,\s+\d{4})?)/i); if (dateMatch) date = dateMatch[1]; const timeMatch = ariaLabel.match(/(\d{1,2}(?::\d{2})?\s*(?:AM|PM|am|pm)(?:\s*[-–]\s*\d{1,2}(?::\d{2})?\s*(?:AM|PM|am|pm)?)?)/); if (timeMatch) time = timeMatch[1]; } else { title = (el.textContent || '').trim(); } if (!title) return; const link = el.querySelector('a[href]') || (el.tagName === 'A' ? el : null); const url = link ? link.href : ''; results.push({ title: title.substring(0, 200), date: date, time: time, event_id: eventId, url: url }); }); return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
